// Parse RSS XML from both feeds, dedup against Supabase, insert new items
const SUPABASE_URL = '<OPTIMAL_SUPABASE_URL>';
const SUPABASE_KEY = '<OPTIMAL_SUPABASE_SERVICE_KEY>';

const items = [];

for (const input of $input.all()) {
  const xml = input.json.data || input.json.body || '';
  const xmlStr = typeof xml === 'string' ? xml : JSON.stringify(xml);

  const itemRegex = /<item>(.*?)<\/item>/gs;
  let match;

  while ((match = itemRegex.exec(xmlStr)) !== null) {
    const itemXml = match[1];
    const getTag = (tag) => {
      const m = itemXml.match(new RegExp(`<${tag}>(.*?)<\/${tag}>`, 's'));
      return m ? m[1].replace(/<!\[CDATA\[|\]\]>/g, '').trim() : null;
    };

    const title = getTag('title');
    const link = getTag('link');
    const description = getTag('description');
    const pubDate = getTag('pubDate');
    const source = link && link.includes('github.com') ? 'github' : 'rss';

    items.push({
      source,
      source_url: link,
      source_account: 'anthropics',
      topic: 'openclaw',
      title,
      content: (description || title || 'No content').substring(0, 2000),
      raw_json: { title, link, description, pubDate },
      scraped_at: new Date().toISOString(),
    });
  }
}

// Deduplicate locally by source_url
const seen = new Set();
const unique = items.filter(item => {
  if (!item.source_url || seen.has(item.source_url)) return false;
  seen.add(item.source_url);
  return true;
});

if (unique.length === 0) {
  return [{ json: { inserted: 0, message: 'No items parsed' } }];
}

// Check existing URLs in Supabase
const existingRes = await fetch(
  `${SUPABASE_URL}/rest/v1/content_scraped_items?select=source_url`,
  { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` } }
);
const existing = await existingRes.json();
const existingUrls = new Set((existing || []).map(e => e.source_url));

const newItems = unique.filter(item => !existingUrls.has(item.source_url));

if (newItems.length === 0) {
  return [{ json: { inserted: 0, message: 'All items already exist' } }];
}

// Batch insert
const insertRes = await fetch(
  `${SUPABASE_URL}/rest/v1/content_scraped_items`,
  {
    method: 'POST',
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      Prefer: 'return=minimal',
    },
    body: JSON.stringify(newItems),
  }
);

if (!insertRes.ok) {
  const errText = await insertRes.text();
  return [{ json: { inserted: 0, error: `Insert failed (${insertRes.status}): ${errText}` } }];
}

return [{ json: { inserted: newItems.length, total_parsed: unique.length, message: `Inserted ${newItems.length} new items` } }];

